const raw = $input.first().json;
const body = raw.body || raw;

// Build rich text for embedding with metadata
const chunks = [];
const dealText = [
  `Deal: ${body.deal_name || 'Unnamed Deal'}`,
  `Company: ${body.company || 'N/A'}`,
  `Description: ${body.description || ''}`,
  `Vehicle: ${body.vehicle || body.vehicle_model || 'N/A'}`,
  `Value: AED ${body.value || body.amount || 'N/A'}`,
  `Status: ${body.status || 'closed-won'}`,
  `Salesperson: ${body.salesperson || 'N/A'}`,
  `Date: ${body.date || new Date().toISOString()}`
].join(' | ');

// Chunk the text if too long (500 char chunks with 50 overlap)
const maxChunkSize = 500;
const overlap = 50;
if (dealText.length <= maxChunkSize) {
  chunks.push({ text: dealText, chunk_index: 0 });
} else {
  let i = 0, idx = 0;
  while (i < dealText.length) {
    const end = Math.min(i + maxChunkSize, dealText.length);
    chunks.push({ text: dealText.substring(i, end), chunk_index: idx++ });
    i += maxChunkSize - overlap;
  }
}

return chunks.map(c => ({ json: {
  document_id: body.id || `deal_${Date.now()}`,
  title: body.deal_name || 'Deal Record',
  department: 'sales',
  content: c.text,
  chunk_index: c.chunk_index,
  metadata: {
    type: 'deal',
    vehicle: body.vehicle || null,
    value_aed: body.value || null,
    source: 'crm_webhook',
    created_at: new Date().toISOString()
  }
}}));

const response = $input.first().json;
const docInfo = $node['Chunk & Enrich'].json;

let embedding;
if (response.data?.[0]?.embedding) {
  embedding = response.data[0].embedding;
} else {
  // If embedding fails after retries, skip this chunk
  return [{ json: { skip: true, error: 'Embedding generation failed', document_id: docInfo.document_id } }];
}

return [{ json: {
  document_id: docInfo.document_id,
  title: docInfo.title,
  department: docInfo.department,
  chunk_index: docInfo.chunk_index,
  content: docInfo.content,
  embedding: JSON.stringify(embedding),
  metadata: docInfo.metadata
}}];
